async function seed() {
  const MONGODB_URI = process.env.MONGODB_URI;
  if (!MONGODB_URI) { console.error("[seed:missing] MONGODB_URI not found."); process.exit(1); }
  console.log("[seed:missing] Connecting to MongoDB...");
  await mongoose.connect(MONGODB_URI);
  console.log("[seed:missing] Connected.");
  const { default: FoodItem } = await import("../models/FoodItem.model.js");
  let upserted = 0, errors = 0;
  for (const dish of MISSING_DISHES) {
    try {
      await FoodItem.updateOne({ canonical_name: dish.canonical_name }, { $set: { ...dish, last_updated: new Date() } }, { upsert: true });
      upserted++;
    } catch (err) {
      errors++;
      console.error(`[seed:missing] Error on "${dish.display_name_en}":`, err.message);
    }
  }
  console.log(`\n[seed:missing] Done! Upserted: ${upserted}/${MISSING_DISHES.length}, Errors: ${errors}`);
  await mongoose.disconnect();
  process.exit(0);
}
seed().catch(err => { console.error("[seed:missing] Fatal:", err); process.exit(1); });
